/// </summary>
[ExtensionOf(formStr(SalesEditLines))]
internal final class ETGSalesEditLines_Extension
{
}

Method.Source:
/// <summary>
/// Making the form control visible when Cylinder tracking flag is enabled.
/// Making the form control visible when Quality parameters flag is enabled.
/// </summary>
public void init()
{
    next init();

    boolean isCylinderTrackingEnabled = SalesParameters::find().ETGEnableCylinderTracking;
    FormRun formRun = this as FormRun;
    formRun.design().controlName(FormControlstr(SalesEditLines, SalesParmLine_ETGDepositAmount)).visible(isCylinderTrackingEnabled);
    formRun.design().controlName(FormControlstr(SalesEditLines, SalesParmLine_ETGDepositRate)).visible(isCylinderTrackingEnabled);
    formRun.design().controlName(FormControlstr(SalesEditLines, SalesParmLine_ETGExciseDuty)).visible(isCylinderTrackingEnabled);
    formRun.design().controlName(FormControlstr(SalesEditLines, SalesParmLine_ETGFilledOrEmpty)).visible(isCylinderTrackingEnabled);
    formRun.design().controlName(FormControlstr(SalesEditLines, SalesParmLine_ETGConnectionType)).visible(isCylinderTrackingEnabled);
    // Code added by Datta - 26/9/2024 - requirement from H011
    formRun.design().controlName("ETGWaybillDetails").visible(ETG_Parameters::find().ETGWaybilldetails);
    // Code added by Datta - 26/9/2024 - requirement from H011
}
